#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[10005];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        long long first = 0, third = 0;
        int idx = 0;
        char *token = strtok(line, " ");
        while (token != NULL) {
            long long val = atoll(token);
            if (idx == 0) first = val;
            if (idx == 2) third = val;
            idx++;
            token = strtok(NULL, " ");
        }
        printf("%lld\n", first * third);
    }
    return 0;
}

