import sys
def main():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        nums = list(map(int, data[i].split()))
        out.append(str(nums[0] * nums[2]))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    main()

